{
  "treatments": [
    {
      "rank": 1,
      "name": "Partial Glossectomy with Elective Neck Dissection",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 9.2,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "Phase 3 RCT evidence from landmark trial (596 patients, T1-T2N0 OCSCC) demonstrating superior 3-year OS with elective neck dissection (80.0% vs 67.5%). NCCN Category 1 recommendation for surgery-first approach in early-stage oral cavity SCC"
        },
        "survival_benefit": {
          "score": 9,
          "rationale": "3-year OS 80.0% with upfront END. 5-year OS for low-risk pT1-T2N0 managed by partial glossectomy and neck dissection is excellent. Local control rate of 80-90% for T1-T2 cancers with single-modality surgery. For T2 with DOI >=4mm, END improves OS with HR 0.37"
        },
        "accessibility": {
          "score": 10,
          "rationale": "Universally available surgical procedure at all head and neck cancer centers. Standard of care per NCCN and ESMO guidelines worldwide"
        },
        "safety_profile": {
          "score": 7,
          "rationale": "Partial glossectomy is well-tolerated with short-term speech and swallowing deficits that recover to near-baseline by 6-12 months. Neck dissection adds shoulder dysfunction risk. Surgical mortality is low (<1%). Diabetes may slightly increase wound healing risk"
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "No biomarker requirements. Surgery is the universal primary treatment for resectable oral cavity SCC regardless of PD-L1 or mutational status"
        }
      },
      "mechanism_of_action": "Surgical excision of the primary tongue tumor with adequate margins (>=5mm) combined with ipsilateral or bilateral selective neck dissection (levels I-III/IV) to remove the primary tumor and address occult nodal metastases. For T2 tumors, depth of invasion >=4mm strongly supports elective neck dissection given 45.7% 5-year risk of regional disease.",
      "key_evidence": {
        "study_name": "Elective versus Therapeutic Neck Dissection in Node-Negative Oral Cancer (D'Cruz et al.)",
        "journal": "New England Journal of Medicine",
        "year": 2015,
        "sample_size": 596,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.63,
          "p_value": 0.01
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "temporary speech impairment (resolves by 12 months in most patients)",
        "short-term dysphagia (recovers by 6 months)",
        "shoulder dysfunction from neck dissection",
        "marginal mandibular nerve injury risk",
        "wound infection (increased risk with diabetes)",
        "orocutaneous fistula risk"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — universally available at all head and neck surgical centers",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa1506007",
        "https://pubmed.ncbi.nlm.nih.gov/23184439/",
        "https://acsjournals.onlinelibrary.wiley.com/doi/10.1002/cncr.27872",
        "https://www.nccn.org/patients/guidelines/content/PDF/hn-oral-patient.pdf"
      ]
    },
    {
      "rank": 2,
      "name": "Adjuvant Cisplatin-Based Chemoradiation (High-Risk Pathology)",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 8.5,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "Phase 3 RCT (EORTC 22931) with 334 patients established concurrent cisplatin-RT as standard for high-risk resected HNSCC. 3-year DFS 59% vs 41% for RT alone. NCCN Category 1 for positive margins and extranodal extension"
        },
        "survival_benefit": {
          "score": 8,
          "rationale": "3-year DFS 59% vs 41% (HR 0.75, p=0.04). Locoregional control 51.4% vs 35.6% for chemoRT vs RT alone. Cisplatin cumulative dose >=200 mg/m2 confers survival benefit with median DFS 20.8 vs 10.5 months"
        },
        "accessibility": {
          "score": 10,
          "rationale": "Cisplatin universally available. Standard chemotherapy regimen at all oncology centers"
        },
        "safety_profile": {
          "score": 4,
          "rationale": "Significant toxicity: grade 3+ mucositis substantially increased, nephrotoxicity (critical concern with diabetes), ototoxicity, myelosuppression. Diabetic patients require careful renal monitoring and dose adjustments. Mucositis and dysphagia significantly higher than RT alone"
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "No biomarker requirement. Indicated by pathologic risk features (positive margins, ENE, multiple positive nodes). Not routinely needed for pT2N0 unless adverse pathologic features found"
        }
      },
      "mechanism_of_action": "Cisplatin (100 mg/m2 every 3 weeks or 40 mg/m2 weekly) administered concurrently with radiation therapy. Cisplatin forms DNA crosslinks causing cell death and acts as a radiosensitizer, enhancing radiation-induced tumor kill. Combined modality addresses microscopic residual disease after surgery.",
      "key_evidence": {
        "study_name": "EORTC 22931 - Postoperative Concurrent Radiotherapy and Chemotherapy for High-Risk HNSCC",
        "journal": "New England Journal of Medicine",
        "year": 2004,
        "sample_size": 334,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.75,
          "p_value": 0.04
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "severe mucositis (grade 3+ in 50-60%)",
        "nephrotoxicity (critical with type 2 diabetes)",
        "ototoxicity",
        "myelosuppression",
        "severe dysphagia requiring feeding tube",
        "nausea and vomiting",
        "weight loss",
        "hyperglycemia exacerbation in diabetic patients"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — universally available",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa032646",
        "https://ccij-online.org/article/concurrent-cisplatin-based-chemotherapy-versus-radiotherapy-alone-as-adjuvant-therapy-for-squamous-cell-carcinoma-of-the-oral-cavity-bearing-high-risk-features-467",
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC6036002/"
      ]
    },
    {
      "rank": 3,
      "name": "Sentinel Lymph Node Biopsy (Alternative to Elective Neck Dissection)",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 8.2,
      "rating_breakdown": {
        "evidence_level": {
          "score": 8,
          "rationale": "Multiple prospective studies and meta-analyses demonstrating comparable oncologic outcomes to END in cT1-T2N0 OCSCC. Pooled sensitivity of 82-87% and negative predictive value of 94%. NCCN-endorsed alternative to END"
        },
        "survival_benefit": {
          "score": 8,
          "rationale": "Overall survival and disease-free survival not significantly different from END in prospective studies. Comparable oncologic outcomes with reduced surgical morbidity. 70-80% of END patients are ultimately N0, making SLNB a more proportionate intervention"
        },
        "accessibility": {
          "score": 7,
          "rationale": "Available at experienced head and neck cancer centers with nuclear medicine and pathology expertise. Requires specialized training and institutional protocols. Not universally available at all centers"
        },
        "safety_profile": {
          "score": 9,
          "rationale": "Significantly lower morbidity than END. Avoids unnecessary full neck dissection in 70-80% of patients. Reduced shoulder dysfunction, reduced operative time, shorter hospital stay. Cost-effective at EUR 3356 per QALY gained"
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "No biomarker requirements. Applicable to all cT1-T2N0 oral cavity SCC patients regardless of molecular profile"
        }
      },
      "mechanism_of_action": "Radiotracer and/or blue dye injection around the primary tumor identifies the first draining lymph node(s) in the cervical chain. These sentinel nodes are surgically removed and examined by serial sectioning and immunohistochemistry. If positive, completion neck dissection is performed; if negative, full neck dissection is avoided, sparing morbidity.",
      "key_evidence": {
        "study_name": "Sentinel Lymph Node Biopsy in Early Oral Cavity Tumors: Evaluation of Oncologic Efficacy (Multi-institutional prospective studies)",
        "journal": "Cancer Medicine / Cancers (MDPI)",
        "year": 2025,
        "sample_size": 300,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0,
          "p_value": 0
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "minor surgical site complications",
        "allergic reaction to dye (rare)",
        "false-negative risk (6-13%)",
        "potential need for completion neck dissection if positive"
      ],
      "qol_impact": null,
      "availability": "Available at specialized head and neck cancer centers — NCCN-endorsed alternative",
      "source_urls": [
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC12171548/",
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC12524105/",
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC12875840/",
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC11081060/"
      ]
    },
    {
      "rank": 4,
      "name": "Adjuvant Radiation Therapy (60-66 Gy IMRT)",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 8.1,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "NCCN Category 1 recommendation for adjuvant RT when adverse pathologic features are present (close margins, PNI, LVI, pT3-4, positive nodes). Extensive retrospective and prospective data supporting its use in intermediate-risk oral cavity SCC"
        },
        "survival_benefit": {
          "score": 7,
          "rationale": "Local control rate of 80-90% for T1-T2 cancers. Adjuvant RT reduces locoregional recurrence in patients with adverse pathologic features. For this T2N0 patient, RT may only be needed if pathology reveals close margins, DOI >4mm, PNI, or LVI"
        },
        "accessibility": {
          "score": 10,
          "rationale": "IMRT widely available at radiation oncology centers worldwide. Standard equipment and technique with well-established dose-fractionation schedules"
        },
        "safety_profile": {
          "score": 5,
          "rationale": "Significant toxicity including mucositis, xerostomia, dysgeusia, radiation caries, and osteoradionecrosis risk. Diabetes compounds mucositis severity and healing complications. Poor dental hygiene baseline increases radiation caries risk substantially"
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "No biomarker requirements. Decision based on pathologic risk features rather than molecular markers"
        }
      },
      "mechanism_of_action": "Intensity-modulated radiation therapy delivers conformal high-dose radiation (60-66 Gy in 30-33 fractions) to the tumor bed and at-risk nodal regions while sparing normal structures. Radiation causes DNA double-strand breaks leading to cancer cell death. IMRT technique minimizes dose to contralateral parotid gland to preserve salivary function.",
      "key_evidence": {
        "study_name": "Post-operative Radiotherapy for Oral Cavity SCC Risk Stratification Studies",
        "journal": "Radiotherapy and Oncology / Head & Neck",
        "year": 2025,
        "sample_size": 500,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0,
          "p_value": 0
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "oral mucositis (grade 3+ in 30-50%)",
        "xerostomia (dry mouth)",
        "dysgeusia (taste changes)",
        "radiation-induced caries",
        "osteoradionecrosis of mandible",
        "fibrosis and trismus",
        "dysphagia",
        "exacerbated complications in diabetic patients"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — universally available",
      "source_urls": [
        "https://www.thegreenjournal.com/article/S0167-8140(25)00175-6/fulltext",
        "https://www.nccn.org/patients/guidelines/content/PDF/hn-oral-patient.pdf",
        "https://jnccn.org/view/journals/jnccn/23/2/article-p2.xml"
      ]
    },
    {
      "rank": 5,
      "name": "Cetuximab + Radiation (Cisplatin-Ineligible Alternative)",
      "category": "Approved Targeted Therapy",
      "intent": null,
      "composite_rating": 8.0,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "Phase 3 RCT (Bonner trial, 424 patients) demonstrating median OS 49.0 months with cetuximab+RT vs 29.3 months with RT alone. FDA-approved for locally advanced HNSCC"
        },
        "survival_benefit": {
          "score": 7,
          "rationale": "Median OS 49.0 vs 29.3 months with RT alone. However, inferior to cisplatin+RT in head-to-head trials (RTOG 1016). Primarily indicated when cisplatin is contraindicated. For this diabetic patient, may be considered if renal function precludes cisplatin"
        },
        "accessibility": {
          "score": 9,
          "rationale": "FDA approved for locally advanced HNSCC in combination with radiation. Widely available but requires IV infusion infrastructure and monitoring for infusion reactions"
        },
        "safety_profile": {
          "score": 7,
          "rationale": "Better renal safety profile than cisplatin — advantageous for diabetic patients. Main toxicities: acneiform rash (80%, correlates with response), infusion reactions, hypomagnesemia. No nephrotoxicity or ototoxicity"
        },
        "biomarker_match": {
          "score": 8,
          "rationale": "EGFR is overexpressed in ~90% of HNSCC. No specific biomarker testing required for use. EGFR expression does not predict response. NOTCH1 status does not affect cetuximab efficacy"
        }
      },
      "mechanism_of_action": "Cetuximab is a chimeric IgG1 monoclonal antibody targeting the extracellular domain of EGFR, blocking ligand binding and receptor activation. Inhibits downstream RAS/MAPK and PI3K/AKT signaling. Additionally triggers antibody-dependent cellular cytotoxicity (ADCC) through Fc-mediated engagement of immune effector cells. Acts as a radiosensitizer.",
      "key_evidence": {
        "study_name": "Bonner et al. - Radiotherapy plus Cetuximab for HNSCC",
        "journal": "New England Journal of Medicine",
        "year": 2006,
        "sample_size": 424,
        "os_months": {
          "treatment": 49,
          "control": 29.3,
          "hazard_ratio": 0.74,
          "p_value": 0.03
        },
        "pfs_months": {
          "treatment": 17.1,
          "control": 12.4
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "acneiform rash (80%, grade 3+ in 17%)",
        "infusion reactions (3% severe)",
        "hypomagnesemia",
        "mucositis (when combined with RT)",
        "radiodermatitis enhancement",
        "fatigue"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — available at oncology centers with IV infusion capabilities",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa053422",
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC3665438/",
        "https://www.sciencedirect.com/science/article/abs/pii/S1040842821002122"
      ]
    },
    {
      "rank": 6,
      "name": "Free Flap Reconstruction (Post-Glossectomy Rehabilitation)",
      "category": "Surgical Rehabilitation",
      "intent": null,
      "composite_rating": 7.6,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "Extensive literature and decades of clinical experience supporting free flap reconstruction as standard of care after significant tongue resection. Radial forearm free flap is the most common and well-studied approach"
        },
        "survival_benefit": {
          "score": 6,
          "rationale": "Does not directly improve cancer survival but critically impacts quality of life, functional outcomes, and rehabilitation. Enables adequate oral function for nutrition, reducing cancer cachexia risk. Near-normal swallowing function achievable 15+ years post-treatment"
        },
        "accessibility": {
          "score": 8,
          "rationale": "Available at major head and neck cancer centers with microsurgical expertise. Requires microsurgeon, specialized nursing, and ICU monitoring. Not available at all centers"
        },
        "safety_profile": {
          "score": 6,
          "rationale": "Major surgery with flap failure risk (2-5%), donor site morbidity, prolonged hospital stay. Diabetes increases wound healing complications and flap failure risk. Requires careful perioperative glucose management"
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Universally applicable to patients requiring tongue reconstruction. No biomarker considerations. Decision based on extent of resection and functional deficit"
        }
      },
      "mechanism_of_action": "Microvascular free tissue transfer (most commonly radial forearm free flap or anterolateral thigh flap) provides vascularized tissue to reconstruct tongue defects after glossectomy. Restores tongue bulk for swallowing and provides mucosal coverage. Maintains residual tongue mobility to optimize speech and deglutition outcomes.",
      "key_evidence": {
        "study_name": "Multi-institutional longitudinal study of partial glossectomy functional outcomes",
        "journal": "Journal of Otolaryngology - Head & Neck Surgery",
        "year": 2017,
        "sample_size": 75,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0,
          "p_value": 0
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "flap failure (2-5%, increased with diabetes)",
        "donor site morbidity",
        "temporary speech impairment",
        "dysphagia during recovery",
        "venous congestion",
        "wound infection (increased in diabetics)"
      ],
      "qol_impact": null,
      "availability": "Available at specialized head and neck cancer centers with microsurgical capabilities",
      "source_urls": [
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC5583999/",
        "https://journalotohns.biomedcentral.com/articles/10.1186/s40463-017-0234-y",
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC6408244/",
        "https://www.sciencedirect.com/science/article/pii/S1808869421001324"
      ]
    },
    {
      "rank": 7,
      "name": "Pembrolizumab + Platinum + 5-FU (Recurrent/Metastatic Setting)",
      "category": "Immunotherapy",
      "intent": null,
      "composite_rating": 7.3,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "Phase 3 RCT KEYNOTE-048 with 882 patients and 5-year follow-up. Established as standard of care for recurrent/metastatic HNSCC. FDA approved first-line for R/M HNSCC"
        },
        "survival_benefit": {
          "score": 5,
          "rationale": "Total population: median OS 13.0 vs 10.7 months (HR 0.72, p=0.0007). However, for PD-L1 CPS <1 (this patient), benefit is substantially attenuated — pembrolizumab monotherapy showed no benefit in CPS <1 subgroup. Combination chemo+pembro still beneficial but less so"
        },
        "accessibility": {
          "score": 10,
          "rationale": "FDA approved first-line for R/M HNSCC. Pembrolizumab widely available globally. Would only apply if disease recurs or metastasizes"
        },
        "safety_profile": {
          "score": 7,
          "rationale": "Manageable immune-related adverse events. Risk of immune-mediated endocrinopathies including new-onset diabetes or worsening glycemic control in existing T2DM. Requires monitoring of thyroid function and blood glucose"
        },
        "biomarker_match": {
          "score": 3,
          "rationale": "PD-L1 CPS <1 is the least favorable biomarker profile for pembrolizumab. Monotherapy shows minimal benefit in CPS <1. Combination with chemotherapy still approved regardless of CPS but reduced magnitude of benefit. NOTCH1 mutation may partially offset low PD-L1 via increased TMB"
        }
      },
      "mechanism_of_action": "Pembrolizumab (anti-PD-1 monoclonal antibody) blocks the PD-1/PD-L1 immune checkpoint axis, restoring T-cell mediated anti-tumor immunity. Combined with platinum chemotherapy (cisplatin or carboplatin) and 5-fluorouracil for cytotoxic synergy. Immunotherapy reactivates exhausted tumor-infiltrating lymphocytes.",
      "key_evidence": {
        "study_name": "KEYNOTE-048",
        "journal": "Journal of Clinical Oncology",
        "year": 2022,
        "sample_size": 882,
        "os_months": {
          "treatment": 13.0,
          "control": 10.7,
          "hazard_ratio": 0.72,
          "p_value": 0.0007
        },
        "pfs_months": {
          "treatment": 5.1,
          "control": 5.0
        },
        "orr_percent": {
          "treatment": 36,
          "control": 36
        }
      },
      "biomarker_requirements": [
        "FDA approved regardless of PD-L1 CPS for combination regimen",
        "PD-L1 CPS >=1 required for monotherapy",
        "Greatest benefit in CPS >=20"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "immune-mediated thyroiditis",
        "pneumonitis",
        "colitis",
        "hepatitis",
        "potential worsening of diabetes/hyperglycemia",
        "immune-mediated type 1 diabetes (rare but reported)",
        "chemotherapy-related nausea, myelosuppression"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — first-line R/M HNSCC (applicable only if disease recurs/metastasizes)",
      "source_urls": [
        "https://ascopubs.org/doi/10.1200/JCO.21.02508",
        "https://www.fda.gov/drugs/resources-information-approved-drugs/fda-approves-pembrolizumab-first-line-treatment-head-and-neck-squamous-cell-carcinoma"
      ]
    },
    {
      "rank": 8,
      "name": "Nivolumab (Second-Line for Recurrent/Metastatic Disease)",
      "category": "Immunotherapy",
      "intent": null,
      "composite_rating": 7.1,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "Phase 3 RCT CheckMate 141 with 361 patients. FDA approved for platinum-refractory R/M HNSCC regardless of PD-L1 status"
        },
        "survival_benefit": {
          "score": 5,
          "rationale": "Median OS 7.5 vs 5.1 months (HR 0.70, p=0.01). ORR 13.3% vs 5.8%. 2-year OS rate 16.9% vs 6.0%. Modest benefit in PD-L1 low/negative tumors. For this patient with CPS <1, benefit is uncertain but approved regardless"
        },
        "accessibility": {
          "score": 9,
          "rationale": "FDA approved for platinum-refractory R/M HNSCC regardless of PD-L1 status. Widely available at oncology centers. Only applicable if disease recurs after primary treatment"
        },
        "safety_profile": {
          "score": 8,
          "rationale": "Lower toxicity than standard chemotherapy. Grade 3-4 AEs 13.1% vs 35.1% for investigator's choice. Well-tolerated immune-related AEs. Manageable in diabetic patients with monitoring"
        },
        "biomarker_match": {
          "score": 4,
          "rationale": "Approved regardless of PD-L1 status, but benefit is attenuated in PD-L1 negative tumors. NOTCH1 mutation may enhance immunogenicity via higher TMB, potentially improving response despite low CPS"
        }
      },
      "mechanism_of_action": "Nivolumab is a fully human IgG4 anti-PD-1 monoclonal antibody that blocks the PD-1 receptor on T cells, preventing engagement with PD-L1/PD-L2 on tumor cells. This restores T-cell effector function and anti-tumor immune response in the tumor microenvironment.",
      "key_evidence": {
        "study_name": "CheckMate 141",
        "journal": "New England Journal of Medicine",
        "year": 2016,
        "sample_size": 361,
        "os_months": {
          "treatment": 7.5,
          "control": 5.1,
          "hazard_ratio": 0.7,
          "p_value": 0.01
        },
        "pfs_months": {
          "treatment": 2.0,
          "control": 2.3
        },
        "orr_percent": {
          "treatment": 13,
          "control": 6
        }
      },
      "biomarker_requirements": [
        "None required (FDA approved regardless of PD-L1)",
        "Greater benefit observed in PD-L1 >=1%"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "fatigue (14%)",
        "immune-mediated thyroiditis",
        "pneumonitis",
        "rash",
        "potential diabetes exacerbation",
        "diarrhea"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — second-line for platinum-refractory R/M HNSCC",
      "source_urls": [
        "https://www.frontiersin.org/journals/oncology/articles/10.3389/fonc.2021.705614/full",
        "https://link.springer.com/article/10.1007/s13402-025-01068-3"
      ]
    },
    {
      "rank": 9,
      "name": "Platinum + 5-FU + Cetuximab (EXTREME Regimen, R/M Setting)",
      "category": "Standard of Care (Recurrent/Metastatic)",
      "intent": null,
      "composite_rating": 7.1,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "Phase 3 RCT EXTREME trial (442 patients) established as standard of care for R/M HNSCC prior to immunotherapy era. Median OS 10.1 vs 7.4 months. Now being supplanted by pembrolizumab-based regimens"
        },
